 44 bool KnownFPClass::isKnownNeverLogicalPosZero(DenormalMode Mode) const {
 45   if (!isKnownNeverPosZero())
 46     return false;
 47 
 48   // If we know there are no denormals, nothing can be flushed to zero.
 49   if (isKnownNeverSubnormal())
 50     return true;
 51 
 52   switch (Mode.Input) {
 53   case DenormalMode::IEEE:
 54     return true;
 55   case DenormalMode::PreserveSign:
 56     // Negative subnormal won't flush to +0
 57     return isKnownNeverPosSubnormal();
 58   case DenormalMode::PositiveZero:
 59   default:
 60     // Both positive and negative subnormal could flush to +0
 61     return false;
 62   }
 63 
 64   llvm_unreachable("covered switch over denormal mode");
 65 }
